def get_dependencies(sentence: str) -> list[tuple[str, str]]:
    words = sentence.lower().split()
    deps = []
    if words and "patient" in words and "shows" in words:
        word_map = {w: i for i, w in enumerate(words)}
        if word_map.get("patient") < word_map.get("shows"):
            deps.append(("shows", "patient"))
        if words.index("signs") < words.index("shows"):
            deps.append(("shows", "signs"))
        if words.index("signs") < words.index("fever"):
            deps.append(("signs", "fever"))
    return deps
